// マーカーアイコン（金色の星★）
function kinnoIcon(){
  return L.divIcon({
    html: '<div style="font-size:14px;line-height:1;color:#f0c000;text-shadow:0 1px 3px rgba(0,0,0,.7),-1px 0 2px rgba(0,0,0,.5),1px 0 2px rgba(0,0,0,.5);display:flex;align-items:center;justify-content:center;">★</div>',
    className: '',
    iconSize: [16, 16],
    iconAnchor: [8, 8],
    popupAnchor: [0, -14]
  });
}

